component.schema:
{
 "description": "ClusterPolicy is the Schema for the clusterpolicies API",
 "properties": {
  "spec": {
   "description": "ClusterPolicySpec defines the desired state of ClusterPolicy",
   "properties": {
    "ccManager": {
     "description": "CCManager component spec",
     "properties": {
      "args": {
       "description": "Optional: List of arguments",
       "items": {
        "type": "string"
       },
       "type": "array"
      },
      "defaultMode": {
       "description": "Default CC mode setting for compatible GPUs on the node",
       "enum": [
        "on",
        "off",
        "devtools"
       ],
       "type": "string"
      },
      "enabled": {
       "description": "Enabled indicates if deployment of CC Manager is enabled",
       "type": "boolean"
      },
      "env": {
       "description": "Optional: List of environment variables",
       "items": {
        "description": "EnvVar represents an environment variable present in a Container.",
        "properties": {
         "name": {
          "description": "Name of the environment variable.",
          "type": "string"
         },
         "value": {
          "description": "Value of the environment variable.",
          "type": "string"
         }
        },
        "required": [
         "name"
        ],
        "type": "object"
       },
       "type": "array"
      },
      "hostNetwork": {
       "description": "HostNetwork indicates whether the CC Manager pod uses the host's network namespace.",
       "type": "boolean"
      },
      "image": {
       "description": "CC Manager image name",
       "pattern": "[a-zA-Z0-9\\-]+",
       "type": "string"
      },
      "imagePullPolicy": {
       "description": "Image pull policy",
       "type": "string"
      },
      "imagePullSecrets": {
       "description": "Image pull secrets",
       "items": {
        "type": "string"
       },
       "type": "array"
      },
      "repository": {
       "description": "CC Manager image repository",
       "type": "string"
      },
      "resources": {
       "description": "Optional: Define resources requests and limits for each pod",
       "properties": {
        "limits": {
         "additionalProperties": {
          "anyOf": [
           {
            "type": "integer"
           },
           {
            "type": "string"
           }
          ],
          "pattern": "^(\\+|-)?(([0-9]+(\\.[0-9]*)?)|(\\.[0-9]+))(([KMGTPE]i)|[numkMGTPE]|([eE](\\+|-)?(([0-9]+(\\.[0-9]*)?)|(\\.[0-9]+))))?$",
          "x-kubernetes-int-or-string": true
         },
         "description": "Limits describes the maximum amount of compute resources allowed.\nMore info: https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/",
         "type": "object"
        },
        "requests": {
         "additionalProperties": {
          "anyOf": [
           {
            "type": "integer"
           },
           {
            "type": "string"
           }
          ],
          "pattern": "^(\\+|-)?(([0-9]+(\\.[0-9]*)?)|(\\.[0-9]+))(([KMGTPE]i)|[numkMGTPE]|([eE](\\+|-)?(([0-9]+(\\.[0-9]*)?)|(\\.[0-9]+))))?$",
          "x-kubernetes-int-or-string": true
         },
         "description": "Requests describes the minimum amount of compute resources required.\nIf Requests is omitted for a container, it defaults to Limits if that is explicitly specified,\notherwise to an implementation-defined value. Requests cannot exceed Limits.\nMore info: https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/",
         "type": "object"
        }
       },
       "type": "object"
      },
      "version": {
       "description": "CC Manager image tag",
       "type": "string"
      }
     },
     "type": "object"
    },
    "cdi": {
     "description": "CDI configures how the Container Device Interface is used in the cluster",
     "properties": {
      "default": {
       "default": false,
       "description": "Deprecated: This field is no longer used. Setting cdi.enabled=true will configure CDI as the default mechanism for making GPUs accessible to containers.",
       "type": "boolean"
      },
      "enabled": {
       "default": true,
       "description": "Enabled indicates whether the Container Device Interface (CDI) should be used as the mechanism for making GPUs accessible to containers.",
       "type": "boolean"
      },
      "nriPluginEnabled": {
       "default": false,
       "description": "NRIPluginEnabled indicates whether an NRI Plugin should be run as a means of injecting CDI devices to gpu management containers.",
       "type": "boolean"
      }
     },
     "type": "object"
    },
    "daemonsets": {
     "description": "Daemonset defines common configuration for all Daemonsets",
     "properties": {
      "annotations": {
       "additionalProperties": {
        "type": "string"
       },
       "description": "Optional: Annotations is an unstructured key value map stored with a resource that may be\nset by external tools to store and retrieve arbitrary metadata. They are not\nqueryable and should be preserved when modifying objects.",
       "type": "object"
      },
      "labels": {
       "additionalProperties": {
        "type": "string"
       },
       "description": "Optional: Map of string keys and values that can be used to organize and categorize\n(scope and select) objects. May match selectors of replication controllers\nand services.",
       "type": "object"
      },
      "podSecurityContext": {
       "description": "Optional: Set pod-level security context for all DaemonSet pods (applies as defaults to all containers)",
       "properties": {
        "appArmorProfile": {
         "description": "appArmorProfile is the AppArmor options to use by the containers in this pod.\nNote that this field cannot be set when spec.os.name is windows.",
         "properties": {
          "localhostProfile": {
           "description": "localhostProfile indicates a profile loaded on the node that should be used.\nThe profile must be preconfigured on the node to work.\nMust match the loaded name of the profile.\nMust be set if and only if type is \"Localhost\".",
           "type": "string"
          },
          "type": {
           "description": "type indicates which kind of AppArmor profile will be applied.\nValid options are:\n  Localhost - a profile pre-loaded on the node.\n  RuntimeDefault - the container runtime's default profile.\n  Unconfined - no AppArmor enforcement.",
           "type": "string"
          }
         },
         "required": [
          "type"
         ],
         "type": "object"
        },
        "fsGroup": {
         "description": "A special supplemental group that applies to all containers in a pod.\nSome volume types allow the Kubelet to change the ownership of that volume\nto be owned by the pod:\n\n1. The owning GID will be the FSGroup\n2. The setgid bit is set (new files created in the volume will be owned by FSGroup)\n3. The permission bits are OR'd with rw-rw----\n\nIf unset, the Kubelet will not modify the ownership and permissions of any volume.\nNote that this field cannot be set when spec.os.name is windows.",
         "format": "int64",
         "type": "integer"
        },
        "fsGroupChangePolicy": {
         "description": "fsGroupChangePolicy defines behavior of changing ownership and permission of the volume\nbefore being exposed inside Pod. This field will only apply to\nvolume types which support fsGroup based ownership(and permissions).\nIt will have no effect on ephemeral volume types such as: secret, configmaps\nand emptydir.\nValid values are \"OnRootMismatch\" and \"Always\". If not specified, \"Always\" is used.\nNote that this field cannot be set when spec.os.name is windows.",
         "type": "string"
        },
        "runAsGroup": {
         "description": "The GID to run the entrypoint of the container process.\nUses runtime default if unset.\nMay also be set in SecurityContext.  If set in both SecurityContext and\nPodSecurityContext, the value specified in SecurityContext takes precedence\nfor that container.\nNote that this field cannot be set when spec.os.name is windows.",
         "format": "int64",
         "type": "integer"
        },
        "runAsNonRoot": {
         "description": "Indicates that the container must run as a non-root user.\nIf true, the Kubelet will validate the image at runtime to ensure that it\ndoes not run as UID 0 (root) and fail to start the container if it does.\nIf unset or false, no such validation will be performed.\nMay also be set in SecurityContext.  If set in both SecurityContext and\nPodSecurityContext, the value specified in SecurityContext takes precedence.",
         "type": "boolean"
        },
        "runAsUser": {
         "description": "The UID to run the entrypoint of the container process.\nDefaults to user specified in image metadata if unspecified.\nMay also be set in SecurityContext.  If set in both SecurityContext and\nPodSecurityContext, the value specified in SecurityContext takes precedence\nfor that container.\nNote that this field cannot be set when spec.os.name is windows.",
         "format": "int64",
         "type": "integer"
        },
        "seLinuxChangePolicy": {
         "description": "seLinuxChangePolicy defines how the container's SELinux label is applied to all volumes used by the Pod.\nIt has no effect on nodes that do not support SELinux or to volumes does not support SELinux.\nValid values are \"MountOption\" and \"Recursive\".\n\n\"Recursive\" means relabeling of all files on all Pod volumes by the container runtime.\nThis may be slow for large volumes, but allows mixing privileged and unprivileged Pods sharing the same volume on the same node.\n\n\"MountOption\" mounts all eligible Pod volumes with `-o context` mount option.\nThis requires all Pods that share the same volume to use the same SELinux label.\nIt is not possible to share the same volume among privileged and unprivileged Pods.\nEligible volumes are in-tree FibreChannel and iSCSI volumes, and all CSI volumes\nwhose CSI driver announces SELinux support by setting spec.seLinuxMount: true in their\nCSIDriver instance. Other volumes are always re-labelled recursively.\n\"MountOption\" value is allowed only when SELinuxMount feature gate is enabled.\n\nIf not specified and SELinuxMount feature gate is enabled, \"MountOption\" is used.\nIf not specified and SELinuxMount feature gate is disabled, \"MountOption\" is used for ReadWriteOncePod volumes\nand \"Recursive\" for all other volumes.\n\nThis field affects only Pods that have SELinux label set, either in PodSecurityContext or in SecurityContext of all containers.\n\nAll Pods that use the same volume should use the same seLinuxChangePolicy, otherwise some pods can get stuck in ContainerCreating state.\nNote that this field cannot be set when spec.os.name is windows.",
         "type": "string"
        },
        "seLinuxOptions": {
         "description": "The SELinux context to be applied to all containers.\nIf unspecified, the container runtime will allocate a random SELinux context for each\ncontainer.  May also be set in SecurityContext.  If set in\nboth SecurityContext and PodSecurityContext, the value specified in SecurityContext\ntakes precedence for that container.\nNote that this field cannot be set when spec.os.name is windows.",
         "properties": {
          "level": {
           "description": "Level is SELinux level label that applies to the container.",
           "type": "string"
          },
          "role": {
           "description": "Role is a SELinux role label that applies to the container.",
           "type": "string"
          },
          "type": {
           "description": "Type is a SELinux type label that applies to the container.",
           "type": "string"
          },
          "user": {
           "description": "User is a SELinux user label that applies to the container.",
           "type": "string"
          }
         },
         "type": "object"
        },
        "seccompProfile": {
         "description": "The seccomp options to use by the containers in this pod.\nNote that this field cannot be set when spec.os.name is windows.",
         "properties": {
          "localhostProfile": {
           "description": "localhostProfile indicates a profile defined in a file on the node should be used.\nThe profile must be preconfigured on the node to work.\nMust be a descending path, relative to the kubelet's configured seccomp profile location.\nMust be set if type is \"Localhost\". Must NOT be set for any other type.",
           "type": "string"
          },
          "type": {
           "description": "type indicates which kind of seccomp profile will be applied.\nValid options are:\n\nLocalhost - a profile defined in a file on the node should be used.\nRuntimeDefault - the container runtime default profile should be used.\nUnconfined - no profile should be applied.",
           "type": "string"
          }
         },
         "required": [
          "type"
         ],
         "type": "object"
        },
        "supplementalGroups": {
         "description": "A list of groups applied to the first process run in each container, in\naddition to the container's primary GID and fsGroup (if specified).  If\nthe SupplementalGroupsPolicy feature is enabled, the\nsupplementalGroupsPolicy field determines whether these are in addition\nto or instead of any group memberships defined in the container image.\nIf unspecified, no additional groups are added, though group memberships\ndefined in the container image may still be used, depending on the\nsupplementalGroupsPolicy field.\nNote that this field cannot be set when spec.os.name is windows.",
         "items": {
          "format": "int64",
          "type": "integer"
         },
         "type": "array",
         "x-kubernetes-list-type": "atomic"
        },
        "supplementalGroupsPolicy": {
         "description": "Defines how supplemental groups of the first container processes are calculated.\nValid values are \"Merge\" and \"Strict\". If not specified, \"Merge\" is used.\n(Alpha) Using the field requires the SupplementalGroupsPolicy feature gate to be enabled\nand the container runtime must implement support for this feature.\nNote that this field cannot be set when spec.os.name is windows.",
         "type": "string"
        },
        "sysctls": {
         "description": "Sysctls hold a list of namespaced sysctls used for the pod. Pods with unsupported\nsysctls (by the container runtime) might fail to launch.\nNote that this field cannot be set when spec.os.name is windows.",
         "items": {
          "description": "Sysctl defines a kernel parameter to be set",
          "properties": {
           "name": {
            "description": "Name of a property to set",
            "type": "string"
           },
           "value": {
            "description": "Value of a property to set",
            "type": "string"
           }
          },
          "required": [
           "name",
           "value"
          ],
          "type": "object"
         },
         "type": "array",
         "x-kubernetes-list-type": "atomic"
        },
        "windowsOptions": {
         "description": "The Windows specific settings applied to all containers.\nIf unspecified, the options within a container's SecurityContext will be used.\nIf set in both SecurityContext and PodSecurityContext, the value specified in SecurityContext takes precedence.\nNote that this field cannot be set when spec.os.name is linux.",
         "properties": {
          "gmsaCredentialSpec": {
           "description": "GMSACredentialSpec is where the GMSA admission webhook\n(https://github.com/kubernetes-sigs/windows-gmsa) inlines the contents of the\nGMSA credential spec named by the GMSACredentialSpecName field.",
           "type": "string"
          },
          "gmsaCredentialSpecName": {
           "description": "GMSACredentialSpecName is the name of the GMSA credential spec to use.",
           "type": "string"
          },
          "hostProcess": {
           "description": "HostProcess determines if a container should be run as a 'Host Process' container.\nAll of a Pod's containers must have the same effective HostProcess value\n(it is not allowed to have a mix of HostProcess containers and non-HostProcess containers).\nIn addition, if HostProcess is true then HostNetwork must also be set to true.",
           "type": "boolean"
          },
          "runAsUserName": {
           "description": "The UserName in Windows to run the entrypoint of the container process.\nDefaults to the user specified in image metadata if unspecified.\nMay also be set in PodSecurityContext. If set in both SecurityContext and\nPodSecurityContext, the value specified in SecurityContext takes precedence.",
           "type": "string"
          }
         },
         "type": "object"
        }
       },
       "type": "object"
      },
      "priorityClassName": {
       "type": "string"
      },
      "rollingUpdate": {
       "description": "Optional: Configuration for rolling update of all DaemonSet pods",
       "properties": {
        "maxUnavailable": {
         "type": "string"
        }
       },
       "type": "object"
      },
      "tolerations": {
       "description": "Optional: Set tolerations",
       "items": {
        "description": "The pod this Toleration is attached to tolerates any taint that matches\nthe triple \u003ckey,value,effect\u003e using the matching operator \u003coperator\u003e.",
        "properties": {
         "effect": {
          "description": "Effect indicates the taint effect to match. Empty means match all taint effects.\nWhen specified, allowed values are NoSchedule, PreferNoSchedule and NoExecute.",
          "type": "string"
         },
         "key": {
          "description": "Key is the taint key that the toleration applies to. Empty means match all taint keys.\nIf the key is empty, operator must be Exists; this combination means to match all values and all keys.",
          "type": "string"
         },
         "operator": {
          "description": "Operator represents a key's relationship to the value.\nValid operators are Exists, Equal, Lt, and Gt. Defaults to Equal.\nExists is equivalent to wildcard for value, so that a pod can\ntolerate all taints of a particular category.\nLt and Gt perform numeric comparisons (requires feature gate TaintTolerationComparisonOperators).",
          "type": "string"
         },
         "tolerationSeconds": {
          "description": "TolerationSeconds represents the period of time the toleration (which must be\nof effect NoExecute, otherwise this field is ignored) tolerates the taint. By default,\nit is not set, which means tolerate the taint forever (do not evict). Zero and\nnegative values will be treated as 0 (evict immediately) by the system.",
          "format": "int64",
          "type": "integer"
         },
         "value": {
          "description": "Value is the taint value the toleration matches to.\nIf the operator is Exists, the value should be empty, otherwise just a regular string.",
          "type": "string"
         }
        },
        "type": "object"
       },
       "type": "array"
      },
      "updateStrategy": {
       "default": "RollingUpdate",
       "enum": [
        "RollingUpdate",
        "OnDelete"
       ],
       "type": "string"
      }
     },
     "type": "object"
    },
    "dcgm": {
     "description": "DCGM component spec",
     "properties": {
      "args": {
       "description": "Optional: List of arguments",
       "items": {
        "type": "string"
       },
       "type": "array"
      },
      "enabled": {
       "description": "Enabled indicates if deployment of NVIDIA DCGM Hostengine as a separate pod is enabled.",
       "type": "boolean"
