           },
           {
            "type": "string"
           }
          ],
          "pattern": "^(\\+|-)?(([0-9]+(\\.[0-9]*)?)|(\\.[0-9]+))(([KMGTPE]i)|[numkMGTPE]|([eE](\\+|-)?(([0-9]+(\\.[0-9]*)?)|(\\.[0-9]+))))?$",
          "x-kubernetes-int-or-string": true
         },
         "description": "Limits describes the maximum amount of compute resources allowed.\nMore info: https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/",
         "type": "object"
        },
        "requests": {
         "additionalProperties": {
          "anyOf": [
           {
            "type": "integer"
           },
           {
            "type": "string"
           }
          ],
          "pattern": "^(\\+|-)?(([0-9]+(\\.[0-9]*)?)|(\\.[0-9]+))(([KMGTPE]i)|[numkMGTPE]|([eE](\\+|-)?(([0-9]+(\\.[0-9]*)?)|(\\.[0-9]+))))?$",
          "x-kubernetes-int-or-string": true
         },
         "description": "Requests describes the minimum amount of compute resources required.\nIf Requests is omitted for a container, it defaults to Limits if that is explicitly specified,\notherwise to an implementation-defined value. Requests cannot exceed Limits.\nMore info: https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/",
         "type": "object"
        }
       },
       "type": "object"
      },
      "service": {
       "description": "Optional: Service configuration for NVIDIA DCGM Exporter",
       "properties": {
        "internalTrafficPolicy": {
         "description": "InternalTrafficPolicy describes how nodes distribute service traffic they receive on the ClusterIP.",
         "type": "string"
        },
        "type": {
         "description": "Type represents the ServiceType which describes ingress methods for a service",
         "type": "string"
        }
       },
       "type": "object"
      },
      "serviceMonitor": {
       "description": "Optional: ServiceMonitor configuration for NVIDIA DCGM Exporter",
       "properties": {
        "additionalLabels": {
         "additionalProperties": {
          "type": "string"
         },
         "description": "AdditionalLabels to add to ServiceMonitor instance for NVIDIA DCGM Exporter",
         "type": "object"
        },
        "enabled": {
         "description": "Enabled indicates if ServiceMonitor is deployed for NVIDIA DCGM Exporter",
         "type": "boolean"
